請問下列程式碼之輸出結果為何？（25 分）
#include <stdio.h>
#include <stdlib.h>
int function(int n)
{
if (n < 10)
return n;
int sum = 0;
while (n > 0)
{
sum += n % 10;
n /= 10;
}
return function(sum);
}
int main()
{
int n = 12345;
int output;
output = function(n);
printf("output%d\n", output);
return 0;
}

